def now_ms() -> int:
    return int(time.time() * 1000)


def clamp(v: float, lo: float, hi: float) -> float:
    return lo if v < lo else hi if v > hi else v


def dist2(a: Tuple[float, float, float], b: Tuple[float, float, float]) -> float:
    dx = a[0] - b[0]
    dy = a[1] - b[1]
    dz = a[2] - b[2]
    return dx * dx + dy * dy + dz * dz


def json_dumps(obj: Any) -> bytes:
    return json.dumps(obj, separators=(",", ":"), ensure_ascii=False).encode("utf-8")


def compress_payload(b: bytes) -> bytes:
    return zlib.compress(b, level=5)


def decompress_payload(b: bytes) -> bytes:
    return zlib.decompress(b)


async def read_exact(reader: asyncio.StreamReader, n: int) -> bytes:
    buf = b""
    while len(buf) < n:
        chunk = await reader.read(n - len(buf))
        if not chunk:
            raise ConnectionError("EOF")
        buf += chunk
    return buf


async def read_frame(reader: asyncio.StreamReader, max_size: int = 2 * 1024 * 1024) -> Tuple[int, bytes]:
    header = await read_exact(reader, 5)
    flags = header[0]
    size = int.from_bytes(header[1:5], "big")
    if size < 0 or size > max_size:
        raise ValueError("Invalid frame size")
    payload = await read_exact(reader, size)
    if flags & 0x1:
        payload = decompress_payload(payload)
    return flags, payload


async def write_frame(writer: asyncio.StreamWriter, payload: bytes, compress: bool = False) -> None:
    flags = 0
    out = payload
    if compress and len(payload) >= 256:
        out = compress_payload(payload)
        flags |= 0x1
    header = bytes([flags]) + len(out).to_bytes(4, "big")
    writer.write(header + out)
    await writer.drain()


